import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find the separator row: a row filled entirely with 4s, if present.
    sep_rows = np.where(np.all(grid == 4, axis=1))[0]
    if len(sep_rows) > 0:
        sep = int(sep_rows[0])
    else:
        sep = h

    # Collect marker cells above the separator.
    markers = []
    for r in range(sep):
        cols = np.where(grid[r] != 0)[0]
        for c in cols:
            markers.append((r, c, int(grid[r, c])))

    if not markers:
        return grid

    # Determine the periodic horizontal template from marker columns.
    cols = sorted(set(c for _, c, _ in markers))
    if len(cols) == 1:
        period = w
        offset = cols[0]
    else:
        diffs = [cols[i + 1] - cols[i] for i in range(len(cols) - 1)]
        period = diffs[0]
        for d in diffs[1:]:
            period = np.gcd(period, d)
        if period <= 0:
            period = w
        offset = cols[0] % period

    # Build a row template of length w using the observed marker colors.
    template = np.zeros(w, dtype=int)
    # Prefer the first observed color for each residue class.
    residue_color = {}
    for _, c, color in markers:
        residue = (c - offset) % period
        if residue not in residue_color:
            residue_color[residue] = color

    for c in range(w):
        residue = (c - offset) % period
        if residue in residue_color:
            template[c] = residue_color[residue]

    # Repeat the template vertically in blocks separated by blank rows.
    out = np.zeros((h, w), dtype=int)
    if sep == h:
        # No separator row; fill all rows with the template.
        for r in range(h):
            out[r] = template
    else:
        block = sep
        for r in range(h):
            if r % block != sep % block:
                out[r] = template
            else:
                out[r] = 0
        # Preserve separator rows as blank rows unless they are explicit 4-rows.
        for r in sep_rows:
            out[r] = 0

    return out

