def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    # Find the separator row: a row filled with 4s, or the first row containing 4.
    sep = None
    for i in range(h):
        if np.all(g[i] == 4):
            sep = i
            break
    if sep is None:
        rows_with_4 = np.where(np.any(g == 4, axis=1))[0]
        if len(rows_with_4) > 0:
            sep = int(rows_with_4[0])
        else:
            sep = h

    # Collect marker colors and their columns from the top section.
    markers = []
    for r in range(sep):
        cols = np.where(g[r] != 0)[0]
        for c in cols:
            markers.append((c, int(g[r, c])))

    # If no markers, return original.
    if not markers:
        return g

    # Sort markers by column, then color.
    markers.sort(key=lambda x: (x[0], x[1]))

    # Determine the repeating horizontal template from marker columns.
    cols = [c for c, _ in markers]
    colors = [v for _, v in markers]

    # Build a row template by repeating the marker pattern across the width.
    # Use the spacing between marker columns if available; otherwise repeat every 2 cells.
    if len(cols) >= 2:
        diffs = [cols[i + 1] - cols[i] for i in range(len(cols) - 1) if cols[i + 1] > cols[i]]
        step = min(diffs) if diffs else 2
    else:
        step = 2

    # Infer a base pattern from the markers in order.
    base_pattern = []
    last_c = None
    for c, v in markers:
        if last_c is None or c != last_c:
            base_pattern.append((c, v))
            last_c = c

    # Create output by tiling the pattern vertically in blocks of (sep) rows,
    # using the top section as the template and repeating it downward.
    out = np.zeros_like(g)

    # Determine rows to fill: every row except blank separator-like rows.
    # The observed rule is to repeat the marker pattern across all rows in each block.
    for r in range(h):
        if r == sep:
            out[r] = g[r]
            continue
        # Fill rows with the repeated horizontal pattern.
        row = np.zeros(w, dtype=int)
        for c, v in markers:
            # Repeat the marker colors across the row with the same periodicity as the marker columns.
            if step <= 0:
                step = 2
            start = c % step
            for x in range(start, w, step):
                row[x] = v
        # If the above doesn't cover enough due to mixed markers, use direct tiling of the sorted sequence.
        if np.count_nonzero(row) == 0:
            seq = [v for _, v in markers]
            if len(seq) == 1:
                row[:] = seq[0]
            else:
                for x in range(w):
                    row[x] = seq[x % len(seq)]
        out[r] = row

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape
    out = np.zeros_like(grid)

    nonzero_rows = np.where(np.any(grid != 0, axis=1))[0]
    if nonzero_rows.size == 0:
        return out

    colors = []
    rows = []
    for r in nonzero_rows:
        vals = grid[r, grid[r] != 0]
        if vals.size > 0:
            colors.append(int(vals[0]))
            rows.append(int(r))

    if not colors:
        return out

    # Use the first nonzero row as the periodic anchor.
    anchor_row = rows[0]
    anchor_color = colors[0]

    # Collect all distinct nonzero colors in order of appearance.
    seen = []
    for c in colors:
        if c not in seen:
            seen.append(c)

    # If there is a divider row of 4s, use colors from non-divider singletons.
    # Otherwise, use all observed colors.
    divider_rows = [r for r in nonzero_rows if np.all(grid[r] == 4)]
    if divider_rows:
        usable_colors = [c for c in seen if c != 4]
        if not usable_colors:
            usable_colors = [4]
    else:
        usable_colors = seen

    # Find rows containing the colors to be expanded.
    color_rows = []
    for r in range(h):
        vals = grid[r, grid[r] != 0]
        if vals.size > 0:
            c = int(vals[0])
            if c in usable_colors:
                color_rows.append((r, c))

    # Expand each colored cell into a full-width stripe, repeated every 2 rows
    # starting from its own row position.
    for r, c in color_rows:
        for rr in range(r, h, 2):
            out[rr, :] = c

    return out

import numpy as np

def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid)
    nonzero_rows = np.where(np.any(grid != 0, axis=1))[0]
    nonzero_cols = np.where(np.any(grid != 0, axis=0))[0]
    if len(nonzero_rows) == 0 or len(nonzero_cols) == 0:
        return np.zeros((0, 0), dtype=grid.dtype)

    r0, r1 = nonzero_rows[0], nonzero_rows[-1] + 1
    c0, c1 = nonzero_cols[0], nonzero_cols[-1] + 1
    cropped = grid[r0:r1, c0:c1]

    rows = np.where(np.any(cropped != 0, axis=1))[0]
    if len(rows) == 0:
        return np.zeros((0, 0), dtype=grid.dtype)

    top_end = rows[0]
    bottom_start = rows[0]
    for i in range(rows[0], cropped.shape[0] - 1):
        if np.any(cropped[i] != 0) and np.any(cropped[i + 1] != 0):
            if np.all(cropped[i + 1] == cropped[rows[0]]):
                bottom_start = i + 1
                break

    top = cropped[:bottom_start]
    bottom = cropped[bottom_start:bottom_start + top.shape[0]]

    if bottom.shape[0] != top.shape[0]:
        h = min(top.shape[0], bottom.shape[0])
        top = top[:h]
        bottom = bottom[:h]

    out = np.where((bottom != 0) & (top == 0), bottom, 0)
    return out.astype(grid.dtype)

