def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    # Find separator rows/cols: full non-zero lines
    sep_rows = [i for i in range(h) if np.all(g[i] != 0)]
    sep_cols = [j for j in range(w) if np.all(g[:, j] != 0)]

    # Assume regular grid with 3x3 tiles separated by 1-cell bars
    row_blocks = []
    prev = 0
    for r in sep_rows + [h]:
        if r > prev:
            row_blocks.append((prev, r))
        prev = r + 1
    col_blocks = []
    prev = 0
    for c in sep_cols + [w]:
        if c > prev:
            col_blocks.append((prev, c))
        prev = c + 1

    # Extract tile colors: each tile is either empty or uniform non-zero
    tiles = [[0 for _ in col_blocks] for _ in row_blocks]
    for i, (r0, r1) in enumerate(row_blocks):
        for j, (c0, c1) in enumerate(col_blocks):
            block = g[r0:r1, c0:c1]
            vals = block[block != 0]
            tiles[i][j] = int(vals[0]) if vals.size else 0

    # Transform by pairing top and bottom tiles in each column of tiles
    out = np.array(g, copy=True)
    for i in range(0, len(row_blocks), 2):
        if i + 1 >= len(row_blocks):
