    for r in range(h - 3):
        for c in range(w - 3):
            block = grid[r:r+4, c:c+4]
            if np.all(block == 5):
                sep_r, sep_c = r, c
                break
        if sep_r is not None:
            break

    if sep_r is None:
        return grid

    # Quadrants around the separator block
    quads = {
        "tl": (slice(0, sep_r), slice(0, sep_c)),
        "tr": (slice(0, sep_r), slice(sep_c + 4, w)),
        "bl": (slice(sep_r + 4, h), slice(0, sep_c)),
        "br": (slice(sep_r + 4, h), slice(sep_c + 4, w)),
    }

    def occupancy(qslice):
        rr, cc = qslice
        sub = grid[rr, cc]
        return (sub != 0).astype(np.int8)

    occ_tl = occupancy(quads["tl"])

    # Choose the quadrant most similar to top-left by occupied positions
    best_name = None
    best_score = None
    for name in ["tr", "bl", "br"]:
