            break
    if color is None:
        return grid

    top1 = grid[0:band_h]
    top2 = grid[band_h:2*band_h]
    bot1 = grid[2*band_h:3*band_h]
    bot2 = grid[3*band_h:4*band_h]

    def bbox(arr):
        ys, xs = np.where(arr == color)
        if len(ys) == 0:
            return None
        return ys.min(), ys.max(), xs.min(), xs.max()

    b1 = bbox(top1)
    b2 = bbox(bot1)
    b3 = bbox(top2)
    b4 = bbox(bot2)

    def extract(arr, b):
        if b is None:
            return None
        y0, y1, x0, x1 = b
        return (arr[y0:y1+1, x0:x1+1] == color).astype(int)

    p1 = extract(top1, b1)
    p2 = extract(bot1, b2)
    p3 = extract(top2, b3)
    p4 = extract(bot2, b4)

    def overlay(lower_band, upper_pat, lower_pat, b_lower):
        if upper_pat is None or lower_pat is None or b_lower is None:
            return lower_band
        y0, y1, x0, x1 = b_lower
        hh = min(upper_pat.shape[0], lower_pat.shape[0])
        ww = min(upper_pat.shape[1], lower_pat.shape[1])
        diff = upper_pat[:hh, :ww] != lower_pat[:hh, :ww]
        out = lower_band.copy()
        for i in range(hh):
            for j in range(ww):
                if diff[i, j]:
                    out[y0 + i, x0 + j] = 1
        return out

    grid[2*band_h:3*band_h] = overlay(bot1, p1, p2, b2)
    grid[3*band_h:4*band_h] = overlay(bot2, p3, p4, b4)
    return grid

