    # Determine the repeating tile from the rows above the separator.
    top = g[:sep_row, :]
    nonzero_rows = np.where(np.any(top != 0, axis=1))[0]
    nonzero_cols = np.where(np.any(top != 0, axis=0))[0]

    if len(nonzero_rows) == 0 or len(nonzero_cols) == 0:
        return np.zeros((0, 0), dtype=int)

    # Smallest row period: distance between repeated non-empty rows.
    if len(nonzero_rows) == 1:
        row_period = 1
    else:
        diffs = np.diff(nonzero_rows)
        row_period = int(diffs[0])
        for d in diffs[1:]:
            row_period = np.gcd(row_period, int(d))
        if row_period == 0:
            row_period = 1

    # Smallest column period: distance between repeated non-empty columns.
    if len(nonzero_cols) == 1:
        col_period = 1
    else:
        diffs = np.diff(nonzero_cols)
        col_period = int(diffs[0])
        for d in diffs[1:]:
            col_period = np.gcd(col_period, int(d))
        if col_period == 0:
            col_period = 1

    # Extract the minimal tile from the upper region.
    tile = np.zeros((row_period, col_period), dtype=int)
    for r in range(row_period):
        for c in range(col_period):
            rr = nonzero_rows[0] + r
            cc = nonzero_cols[0] + c
            if rr < top.shape[0] and cc < top.shape[1]:
                tile[r, c] = top[rr, cc]

    # Build output by tiling the minimal pattern across its own size.
    out = np.zeros((sep_row, w), dtype=int)
    for r in range(sep_row):
        for c in range(w):
            v = tile[r % row_period, c % col_period]
            out[r, c] = color if v != 0 else 0

    return out

