                    if 1 <= nr < h and 0 <= nc < w and not visited[nr, nc] and grid[nr, nc] == color:
                        visited[nr, nc] = True
                        stack.append((nr, nc))

            rows = [r for r, _ in cells]
            cols = [c for _, c in cells]
            r0, r1 = min(rows), max(rows)
            c0, c1 = min(cols), max(cols)
            height = r1 - r0 + 1
            width = c1 - c0 + 1

            # Recolor based on footprint
            if height == 2 and width == 2:
                new_color = c_left
            elif height == 3 and width == 3:
                new_color = c_right
            elif height == 2 and width == 4:
