def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    # Find separator row: the first all-zero row after the top sample row(s)
    sep = None
    for r in range(1, h):
        if np.all(grid[r] == 0):
            sep = r
            break
    if sep is None:
        return grid

    samples = [int(x) for x in grid[0] if x != 0]
    if len(samples) < 3:
        return grid
    left_color, mid_color, right_color = samples[:3]

    # Collect connected nonzero components below separator
    below = grid[sep + 1:]
    bh, bw = below.shape
    visited = np.zeros((bh, bw), dtype=bool)
    comps = []

    dirs = [(1, 0), (-1, 0), (0, 1), (0, -1)]

    for r in range(bh):
        for c in range(bw):
            if below[r, c] == 0 or visited[r, c]:
                continue
            color = int(below[r, c])
            stack = [(r, c)]
            visited[r, c] = True
            cells = []
            while stack:
                x, y = stack.pop()
                cells.append((x, y))
                for dx, dy in dirs:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < bh and 0 <= ny < bw and not visited[nx, ny] and below[nx, ny] != 0:
                        visited[nx, ny] = True
                        stack.append((nx, ny))
            rs = [p[0] for p in cells]
            cs = [p[1] for p in cells]
            comps.append({
                "cells": cells,
                "area": len(cells),
                "bbox": (min(rs), max(rs), min(cs), max(cs)),
                "color": color
            })

    if not comps:
        return grid

    # Rank by area: smallest -> left sample, medium -> middle sample, largest -> right sample
    comps_sorted = sorted(comps, key=lambda d: (d["area"], d["bbox"][0], d["bbox"][2]))
    n = len(comps_sorted)

    for i, comp in enumerate(comps_sorted):
        if n == 1:
            assigned = left_color
        elif n == 2:
            assigned = left_color if i == 0 else right_color
        else:
            if i == 0:
                assigned = left_color
            elif i == n - 1:
                assigned = right_color
            else:
                assigned = mid_color

        r0, r1, c0, c1 = comp["bbox"]
        grid[sep + 1 + r0: sep + 1 + r1 + 1, c0:c1 + 1] = assigned

    return grid

