def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    grid = np.array(input_grid, copy=True)
    h, w = grid.shape

    nz = np.argwhere(grid != 0)
    if nz.size == 0:
        return grid

    # Find the minimal bounding box of the seed pattern
    r0, c0 = nz.min(axis=0)
    r1, c1 = nz.max(axis=0)
    seed = grid[r0:r1 + 1, c0:c1 + 1]

    # Determine the periodic step from the seed's occupied rows/cols
    rows = np.unique(nz[:, 0])
    cols = np.unique(nz[:, 1])

    if len(rows) > 1:
        dr = int(np.min(np.diff(rows)))
    else:
        dr = seed.shape[0]
    if len(cols) > 1:
        dc = int(np.min(np.diff(cols)))
    else:
        dc = seed.shape[1]

    dr = max(dr, 1)
    dc = max(dc, 1)

    out = np.zeros_like(grid)

    # Tile the seed pattern across the grid using the inferred steps
    for rr in range(r0, h, dr):
        for cc in range(c0, w, dc):
            for i in range(seed.shape[0]):
                for j in range(seed.shape[1]):
                    val = seed[i, j]
                    if val != 0:
                        r = rr + i
                        c = cc + j
                        if r < h and c < w:
                            out[r, c] = val

    return out

