def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid)
    h, w = g.shape

    nonzero_rows = np.where(np.any(g != 0, axis=1))[0]
    if len(nonzero_rows) == 0:
        return g.copy()

    # Find separator row: a row that is all background and lies between two non-empty regions
    sep = None
    for r in range(h):
        if np.all(g[r] == 0):
            above = np.any(np.any(g[:r] != 0, axis=1)) if r > 0 else False
            below = np.any(np.any(g[r + 1:] != 0, axis=1)) if r + 1 < h else False
            if above and below:
                sep = r
                break

    if sep is None:
        # Fallback: use bounding box of all nonzero cells
        rows = np.where(np.any(g != 0, axis=1))[0]
        cols = np.where(np.any(g != 0, axis=0))[0]
        return g[rows.min():rows.max() + 1, cols.min():cols.max() + 1].copy()

    top = g[:sep]
    bottom = g[sep + 1:]

    def bbox(arr):
        nz = np.argwhere(arr != 0)
        if nz.size == 0:
            return None
        r0, c0 = nz.min(axis=0)
        r1, c1 = nz.max(axis=0)
        return r0, r1, c0, c1

    bt = bbox(top)
    bb = bbox(bottom)

    if bt is None and bb is None:
        return np.zeros((0, 0), dtype=g.dtype)

    if bt is None:
        r0, r1, c0, c1 = bb
        return bottom[r0:r1 + 1, c0:c1 + 1].copy()

    if bb is None:
        r0, r1, c0, c1 = bt
        return top[r0:r1 + 1, c0:c1 + 1].copy()

    tr0, tr1, tc0, tc1 = bt
    br0, br1, bc0, bc1 = bb

    top_crop = top[tr0:tr1 + 1, tc0:tc1 + 1]
    bot_crop = bottom[br0:br1 + 1, bc0:bc1 + 1]

    out_h = max(top_crop.shape[0], bot_crop.shape[0])
    out_w = max(top_crop.shape[1], bot_crop.shape[1])
    out = np.zeros((out_h, out_w), dtype=g.dtype)

    # Overlay top crop in the upper-left
    out[:top_crop.shape[0], :top_crop.shape[1]] = np.where(
        top_crop != 0, top_crop, out[:top_crop.shape[0], :top_crop.shape[1]]
    )

    # Overlay bottom crop in the lower-right
    r_off = out_h - bot_crop.shape[0]
    c_off = out_w - bot_crop.shape[1]
    region = out[r_off:r_off + bot_crop.shape[0], c_off:c_off + bot_crop.shape[1]]
    out[r_off:r_off + bot_crop.shape[0], c_off:c_off + bot_crop.shape[1]] = np.where(
        bot_crop != 0, bot_crop, region
    )

    return out

