def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape

    rows = np.where(np.any(g == 5, axis=1))[0]
    cols = np.where(np.any(g == 5, axis=0))[0]

    def segments(idxs):
        if len(idxs) == 0:
            return []
        segs = []
        s = idxs[0]
        p = idxs[0]
        for x in idxs[1:]:
            if x == p + 1:
                p = x
            else:
                segs.append((s, p))
                s = p = x
        segs.append((s, p))
        return segs

    rsegs = segments(rows)
    csegs = segments(cols)

    # If there is a single separator row/col, use it as mirror axis.
    # Otherwise, use the central gap between the two main separator bands.
    if len(rsegs) >= 2:
        top_band = rsegs[0]
        bot_band = rsegs[-1]
        r_axis = (top_band[1] + bot_band[0]) / 2.0
    elif len(rsegs) == 1:
        r_axis = rsegs[0][0]
    else:
        r_axis = (h - 1) / 2.0

    if len(csegs) >= 2:
        left_band = csegs[0]
        right_band = csegs[-1]
        c_axis = (left_band[1] + right_band[0]) / 2.0
    elif len(csegs) == 1:
        c_axis = csegs[0][0]
    else:
        c_axis = (w - 1) / 2.0

    # Determine whether the structure is primarily split by rows or columns.
    row_gap = (rows[-1] - rows[0] + 1) if len(rows) else 0
    col_gap = (cols[-1] - cols[0] + 1) if len(cols) else 0

    out = g.copy()

    if row_gap >= col_gap:
        # Mirror across horizontal axis: compare top and bottom halves.
        for i in range(h):
            mi = int(round(2 * r_axis - i))
            if 0 <= mi < h and i < mi:
                for j in range(w):
                    if g[i, j] == 0 and g[mi, j] == 5:
                        out[i, j] = 4
                    elif g[mi, j] == 0 and g[i, j] == 5:
                        out[mi, j] = 4
    else:
        # Mirror across vertical axis: compare left and right halves.
        for j in range(w):
            mj = int(round(2 * c_axis - j))
            if 0 <= mj < w and j < mj:
                for i in range(h):
                    if g[i, j] == 0 and g[i, mj] == 5:
                        out[i, j] = 4
                    elif g[i, mj] == 0 and g[i, j] == 5:
                        out[i, mj] = 4

    return out

