def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    out = g.copy()

    # Find all rows/cols containing 5s
    row_has = np.any(g == 5, axis=1)
    col_has = np.any(g == 5, axis=0)

    # Identify contiguous separator bands
    def bands(mask):
        res = []
        i = 0
        n = len(mask)
        while i < n:
            if mask[i]:
                j = i
                while j < n and mask[j]:
                    j += 1
                res.append((i, j - 1))
                i = j
            else:
                i += 1
        return res

    row_bands = bands(row_has)
    col_bands = bands(col_has)

    # If there is a horizontal separator band, compare regions above/below it.
    for r0, r1 in row_bands:
        top = r0 - 1
        bottom = r1 + 1
        while top >= 0 and bottom < h:
            for c in range(w):
                if g[top, c] == 0 and g[bottom, c] == 5:
                    out[top, c] = 4
                elif g[top, c] == 5 and g[bottom, c] == 0:
                    out[bottom, c] = 4
                elif g[top, c] == 0 and g[bottom, c] == 0:
                    # If one side is zero and the mirrored side is also zero,
                    # mark only when the local neighborhood suggests a mismatch
                    pass
            top -= 1
            bottom += 1

    # If there is a vertical separator band, compare regions left/right of it.
    for c0, c1 in col_bands:
        left = c0 - 1
        right = c1 + 1
        while left >= 0 and right < w:
            for r in range(h):
                if g[r, left] == 0 and g[r, right] == 5:
                    out[r, left] = 4
                elif g[r, left] == 5 and g[r, right] == 0:
                    out[r, right] = 4
                elif g[r, left] == 0 and g[r, right] == 0:
                    pass
            left -= 1
            right += 1

    # More direct rule: within each non-5 region, any 0 that is mirrored to a 5
    # across the nearest separator band becomes 4.
    # Horizontal bands
    for r0, r1 in row_bands:
        for d in range(1, max(r0, h - 1 - r1) + 1):
            r_top = r0 - d
            r_bot = r1 + d
            if r_top < 0 or r_bot >= h:
                break
            for c in range(w):
                if g[r_top, c] == 0 and g[r_bot, c] == 5:
                    out[r_top, c] = 4
                if g[r_bot, c] == 0 and g[r_top, c] == 5:
                    out[r_bot, c] = 4

    # Vertical bands
    for c0, c1 in col_bands:
        for d in range(1, max(c0, w - 1 - c1) + 1):
            c_left = c0 - d
            c_right = c1 + d
            if c_left < 0 or c_right >= w:
                break
            for r in range(h):
                if g[r, c_left] == 0 and g[r, c_right] == 5:
                    out[r, c_left] = 4
                if g[r, c_right] == 0 and g[r, c_left] == 5:
                    out[r, c_right] = 4

    return out

