def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    out = g.copy()

    # Find all connected components of 5s
    visited = np.zeros((h, w), dtype=bool)
    comps = []

    for r in range(h):
        for c in range(w):
            if g[r, c] == 5 and not visited[r, c]:
                stack = [(r, c)]
                visited[r, c] = True
                cells = []
                minr = maxr = r
                minc = maxc = c
                while stack:
                    x, y = stack.pop()
                    cells.append((x, y))
                    if x < minr: minr = x
                    if x > maxr: maxr = x
                    if y < minc: minc = y
                    if y > maxc: maxc = y
                    for dx, dy in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        nx, ny = x + dx, y + dy
                        if 0 <= nx < h and 0 <= ny < w and g[nx, ny] == 5 and not visited[nx, ny]:
                            visited[nx, ny] = True
                            stack.append((nx, ny))
                comps.append((cells, minr, maxr, minc, maxc))

    # For each component, fill its interior with 4 if it forms a frame-like structure.
    # Interior is defined as the bounding box area excluding the 5 outline cells.
    for cells, minr, maxr, minc, maxc in comps:
        if maxr - minr < 2 or maxc - minc < 2:
            continue

        # Determine if this component is frame-like: all 5s lie on the boundary of its bbox
        frame_like = True
        for x, y in cells:
            if not (x == minr or x == maxr or y == minc or y == maxc):
                frame_like = False
                break
        if not frame_like:
            continue

        # Fill interior zeros with 4
        for x in range(minr + 1, maxr):
            for y in range(minc + 1, maxc):
                if out[x, y] == 0:
                    out[x, y] = 4

    return out

