def transform_grid(input_grid: np.ndarray) -> np.ndarray:
    g = np.array(input_grid, copy=True)
    h, w = g.shape
    colors = [c for c in np.unique(g) if c != 0]
    if not colors:
        return g

    # Choose template color as the one with the most cells; reference color as the other nonzero color if present.
    counts = {c: int(np.sum(g == c)) for c in colors}
    template = max(counts, key=counts.get)
    others = [c for c in colors if c != template]
    ref_color = others[0] if others else template

    template_pos = np.argwhere(g == template)
    ref_pos = np.argwhere(g == ref_color)

    # If only one color exists, infer a 4x4 motif from its positions and tile it.
    if ref_color == template:
        rows = np.unique(template_pos[:, 0])
        cols = np.unique(template_pos[:, 1])
        if len(rows) == 0 or len(cols) == 0:
            return g
        r0, c0 = rows.min(), cols.min()
        motif = np.zeros((4, 4), dtype=int)
        for r, c in template_pos:
            motif[(r - r0) % 4, (c - c0) % 4] = template
        out = np.zeros_like(g)
        for i in range(h):
            for j in range(w):
                out[i, j] = motif[i % 4, j % 4]
        return out

    # Determine a 4x4 motif from template cells using their coordinates modulo 4.
    # Align motif so that template cells can be shifted to reference cells.
    motif = np.zeros((4, 4), dtype=int)
    if len(template_pos) > 0:
        r0, c0 = template_pos.min(axis=0)
        for r, c in template_pos:
            motif[(r - r0) % 4, (c - c0) % 4] = template

    # Find a shift that best aligns template positions to reference positions modulo 4.
    template_mod = {(r % 4, c % 4) for r, c in template_pos}
    ref_mod = {(r % 4, c % 4) for r, c in ref_pos}
    best_shift = (0, 0)
    best_score = -1
    for dr in range(4):
        for dc in range(4):
            shifted = {((r + dr) % 4, (c + dc) % 4) for r, c in template_mod}
            score = len(shifted & ref_mod)
            if score > best_score:
                best_score = score
                best_shift = (dr, dc)

    dr, dc = best_shift
    out = np.zeros_like(g)

    # Tile the motif across the whole grid with the chosen shift.
    for i in range(h):
        for j in range(w):
            out[i, j] = motif[(i - dr) % 4, (j - dc) % 4]

